static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    // Input shapes: x: [aLength, rLength], gamma: [rLength], beta: [rLength]
    const gert::Shape *xShape = context->GetInputShape(0);
    const gert::Shape *gammaShape = context->GetInputShape(1);
    const gert::Shape *betaShape = context->GetInputShape(2);

    // Expect x shape has 2 dims (batch, feature) after flattening
    const uint32_t aLength = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
    const uint32_t rLength = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));

    // padding to 32-byte alignment
    constexpr uint32_t typeSize = sizeof(float);
    int32_t alignElems = 32 / typeSize;
    uint32_t rLengthWithPadding = (rLength + alignElems - 1) / alignElems * alignElems;

    // Query workspace size
    ge::Shape geShape({ aLength, rLength });
    uint32_t maxTmpSize = 0;
    uint32_t minTmpSize = 0;
    bool isReuseSource = false;
    AscendC::GetLayerNormMaxMinTmpSize(geShape, sizeof(float), isReuseSource, true, false, maxTmpSize, minTmpSize);

    uint32_t localWorkspaceSize = minTmpSize;

    // Get tiling from API
    LayerNormCustomTilingData tiling;
    AscendC::GetLayerNormNDTilingInfo(geShape, localWorkspaceSize, sizeof(float), isReuseSource, true, tiling);
    tiling.set_aLength(aLength);
    tiling.set_rLength(rLength);
    tiling.set_rLengthWithPadding(rLengthWithPadding);

    // Get epsilon from attribute (default 1e-5)
    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *epsilon = attrs->GetAttrPointer<float>(0);
    tiling.set_epsilon(*epsilon);

    context->SetBlockDim(1);  // single block for simplicity; could be optimized

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

